package com.coagent4u.agent.port.out;

import com.coagent4u.shared.AgentId;
import com.coagent4u.shared.UserId;

/**
 * Outbound port for delegating message processing to the Python LLM Agent Runtime.
 */
public interface PythonAgentPort {
    /**
     * Forwards a Slack message to the Python agent runtime.
     * @param agentId The agent handling the request
     * @param userId The user who sent the request
     * @param rawText The message content
     * @return The exact natural-language response generated by the LLM
     */
    String forwardToPython(AgentId agentId, UserId userId, String rawText);
}
